// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title Stage1 Token Contract
 * @dev 这是一个简单的 ERC20 代币合约，支持代币转账、铸造和卖出功能
 * 
 * 功能特性：
 * 1. 代币转账功能 (transfer)
 * 2. 铸造新代币 (mint) - 仅合约所有者可用
 * 3. 卖出代币换取 ETH (sell) - 按固定价格 600 wei/token
 * 4. 重入攻击防护
 * 5. 合约可被所有者关闭 (close)
 */
contract Stage1 {
    // ============================
    // 重入防护机制
    // ============================

    /**
     * @dev 重入防护锁，防止重入攻击
     * 在关键函数执行期间锁定，阻止嵌套调用
     */
    bool private _locked = false;

    /**
     * @dev 重入防护修饰器
     * 使用检查-效果-交互模式 (Checks-Effects-Interactions) 防止重入攻击
     * 
     * 工作原理：
     * 1. 检查：验证锁未被持有（允许调用）
     * 2. 设置：立即锁定
     * 3. 执行：运行函数主体
     * 4. 解锁：函数返回后释放锁
     * 
     * 注意：由于 Solidity 修饰器的执行顺序，
     * 锁定在函数主体之前设置，在函数主体之后释放
     */
    modifier nonReentrant() {
        require(!_locked, 'Reentrant call');
        _locked = true;
        _;
        _locked = false;
    }

    // ============================
    // 合约状态变量
    // ============================

    /// @dev 合约所有者地址，可用于铸造代币和关闭合约
    address payable public owner;

    // ============================
    // 事件定义
    // ============================

    /**
     * @dev 转账事件
     * @param from 代币转出地址
     * @param to 代币转入地址
     * @param value 转账数量
     */
    event Transfer(address indexed from, address indexed to, uint256 value);

    /**
     * @dev 铸造事件（代币增发）
     * @param to 获得新代币的地址
     * @param value 铸造的代币数量
     */
    event Mint(address indexed to, uint256 value);

    /**
     * @dev 卖出事件（代币销毁并换 ETH）
     * @param from 卖出代币的地址
     * @param value 卖出的代币数量
     */
    event Sell(address indexed from, uint256 value);

    // ============================
    // 常量定义
    // ============================

    /**
     * @dev 代币价格：600 wei 每个代币
     * @notice 这是固定价格，不可更改
     */
    uint128 private constant PRICE_WEI_PER_TOKEN = 600;

    // ============================
    // 内部状态变量
    // ============================

    /// @dev 代币总供应量
    uint256 private _totalSupply;

    /// @dev 代币名称（如 "MyToken"）
    string private _name;

    /// @dev 代币符号（如 "MTK"）
    string private _symbol;

    /**
     * @dev 地址到代币余额的映射
     * @notice 使用 private 修饰符防止直接访问，通过 balanceOf 函数查询
     */
    mapping(address => uint256) private _balances;

    // ============================
    // 构造函数
    // ============================

    /**
     * @dev 构造函数，初始化代币合约
     * @param name 代币名称
     * @param symbol 代币符号
     * 
     * @notice 部署时设置代币名称和符号，合约创建者为所有者
     * @notice 初始代币供应量为 0，需要通过 mint 铸造
     */
    constructor(string memory name, string memory symbol) {
        owner = payable(msg.sender);  // 记录合约部署者地址
        _name = name;
        _symbol = symbol;
    }

    // ============================
    // 只读函数 (View Functions)
    // ============================

    /**
     * @dev 获取代币名称
     * @return 代币名称字符串
     */
    function getName() external view returns (string memory) {
        return _name;
    }

    /**
     * @dev 获取代币总供应量
     * @return 代币总供应量
     */
    function totalSupply() external view returns (uint256) {
        return _totalSupply;
    }

    /**
     * @dev 获取代币符号
     * @return 代币符号字符串
     */
    function getSymbol() external view returns (string memory) {
        return _symbol;
    }

    /**
     * @dev 获取代币价格
     * @return 每个代币的价格（单位：wei）
     * 
     * @notice 纯函数，不读取状态，可用于 gas 优化
     */
    function getPrice() external pure returns (uint128) {
        return PRICE_WEI_PER_TOKEN;
    }

    /**
     * @dev 查询指定地址的代币余额
     * @param account 要查询的地址
     * @return 该地址持有的代币数量
     */
    function balanceOf(address account) external view returns (uint256) {
        return _balances[account];
    }

    // ============================
    // 状态变更函数 (State-Changing Functions)
    // ============================

    /**
     * @dev 转账功能 - 将代币从调用者账户转移到目标账户
     * @param to 接收代币的目标地址
     * @param value 要转账的代币数量
     * @return 是否转账成功
     * 
     * @dev 安全考虑：
     * 1. 检查目标地址不为零地址（防止发送到黑洞地址）
     * 2. 检查发送方余额充足
     * 3. 先减后加余额顺序（防止整数溢出）
     * 
     * @dev 事件说明：
     * 成功时触发 Transfer 事件，记录转账信息
     */
    function transfer(address to, uint256 value) external returns (bool) {
        // 地址有效性校验：不能转账到零地址
        require(to != address(0), "cannot transfer to 0x0");
        // 余额校验：发送方必须有足够的代币
        require(_balances[msg.sender] >= value, "no enough balance");

        // 防止 DAO 攻击：先减后加，确保余额更新原子性
        // 这样可以防止重入攻击和整数溢出问题
        _balances[msg.sender] -= value;
        _balances[to] += value;

        // 记录转账事件，供前端和监控系统监听
        emit Transfer(msg.sender, to, value);
        return true;
    }

    /**
     * @dev 铸造新代币 - 合约所有者专用
     * @param to 接收新代币的地址
     * @param value 要铸造的代币数量
     * @return 是否铸造成功
     * 
     * @dev 安全考虑：
     * 1. 仅允许合约所有者调用（防止非法增发）
     * 2. 检查目标地址不为零（防止烧毁代币）
     * 
     * @dev 经济机制：
     * - 铸造会增加总供应量 (_totalSupply)
     * - 代币直接添加到接收者余额
     * - 触发 Mint 事件记录增发
     * 
     * @notice 这个函数需要信任合约所有者，应在部署时设置合理的所有者权限
     */
    function mint(address to, uint256 value) external returns (bool) {
        // 权限校验：仅合约所有者可以铸造
        require(msg.sender == owner, "only owner may call");
        // 地址校验：不能铸造到零地址
        require(to != address(0), "mint to zero");

        // 增加总供应量
        _totalSupply += value;
        // 增加接收者余额
        _balances[to] += value;
        // 记录铸造事件
        emit Mint(to, value);

        return true;
    }

    /**
     * @dev 卖出代币 - 将代币兑换为 ETH
     * @param value 要卖出的代币数量
     * @return 是否卖出成功
     * 
     * @dev 工作流程：
     * 1. 校验卖出数量大于 0
     * 2. 校验用户有足够代币
     * 3. 校验合约有足够 ETH
     * 4. 扣除用户代币和总供应量
     * 5. 向用户支付 ETH
     * 
     * @dev 安全考虑：
     * 1. 使用 nonReentrant 修饰器防止重入攻击
     * 2. 使用 Checks-Effects-Interactions 模式
     * 3. 先更新状态（扣除代币），再转 ETH（外部调用）
     * 
     * @dev 价格机制：
     * - 单价：600 wei / token
     * - 总价 = 单价 × 数量
     * - 例如：卖出 10 个代币可获得 6000 wei (0.006 ETH)
     * 
     * @notice 重要：合约必须有足够的 ETH 储备才能成功卖出
     */
    function sell(uint256 value) external nonReentrant returns (bool) {
        // 数量校验：不能卖出 0 或负数
        require(value > 0, "cannot sell zero or below");
        // 余额校验：用户必须有足够的代币
        require(_balances[msg.sender] >= value, "no enough balance");

        // 计算应该支付给用户的 ETH 数量
        // 使用 uint256 确保乘法运算不溢出
        uint256 weiRequired = uint256(PRICE_WEI_PER_TOKEN) * value;

        // 合约余额校验：确保合约有足够 ETH 支付用户
        // 这是必要的，因为合约可能没有足够的 ETH 储备
        require(address(this).balance >= weiRequired, "contract insufficient ETH");

        // _checks-Effects-Interactions_：先更新状态，再进行外部调用

        // 扣除用户代币
        _balances[msg.sender] -= value;
        // 减少总供应量（代币被"烧毁"）
        _totalSupply -= value;

        // 记录卖出事件
        emit Sell(msg.sender, value);

        // 向用户支付 ETH
        // 使用 call 而不是 transfer，避免 gas 限制问题
        (bool sent, ) = payable(msg.sender).call{value: weiRequired}("");
        require(sent, "ETH transfer failed");
        return true;
    }

    /**
     * @dev 关闭合约 - 合约所有者专用
     * 
     * @dev 功能：
     * 1. 验证调用者是合约所有者
     * 2. 销毁合约，将合约剩余 ETH 转给所有者
     * 
     * @dev 安全考虑：
     * - 仅所有者可调用
     * - selfdestruct 是不可逆操作
     * 
     * @notice 谨慎使用，确保所有业务逻辑已完成后再调用
     */
    function close() external {
        // 权限校验：仅合约所有者
        require(msg.sender == owner, "only owner");
        // 销毁合约，将余额转给所有者
        selfdestruct(owner);
    }

    /**
     * @dev 接收 ETH 的回调函数
     * 
     * @dev 用途：
     * - 允许任何人向合约充值 ETH
     * - 这是卖出功能所必需的（需要 ETH 储备）
     * 
     * @notice 合约需要 ETH 储备才能支持卖出功能
     * @notice 如果不需要充值功能，可以移除此函数
     */
    receive() external payable {}
}

contracts/2506586525116696Stage2.sol.content:
pragma solidity ^0.8.0;

/**
    接口：调用外部合约Stage1的发放奖励和查询余额函数
**/
interface IStage1 {
    function transfer(address to, uint256 value) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract Stage2{
    // 重入防护锁
    bool private _locked = false;

    // 重入防护修饰器
    modifier nonReentrant() {
        require(!_locked, "Reentrant call");
        _locked = true;
        _;
        _locked = false;
    }

    // 游戏状态枚举
    enum DiceGameState { None, WaitingForB, BothBetted, Settled }
    // stateMachine
    DiceGameState public diceGameState;
    // 发放token合约对象
    IStage1 public tokenContract;
    // 每场赌约的固定token数
    uint16 public constant TOKEN_BONUS = 100; 
    // 超时时间（秒）：30分钟
    uint256 public constant TIMEOUT_DURATION = 30 * 60;

    // 事件
    event DiceGameCreated(address gamblerA, uint256 betAmount, bytes32 fingerPrintForA);
    event DiceGameJoined(address  gamblerB, uint256 betAmount, bytes32 fingerPrintForB);
    event BetForARevealed();
    event BetForBRevealed();
    event DiceGameSettled(address winner, uint256 profits, uint256 stage1TokenBonus);

    // A
    address public gamblerA;
    // A下注结果hash值
    bytes32 public fingerPrintForA;
    bytes32 public secretA;
    bool public revealedA;


    uint256 public betAmount;

    // B
    address public gamblerB;
    // B下注结果hash值
    bytes32 public fingerPrintForB;
    bytes32 public secretB;
    bool public revealedB;

    // winner
    address public winner;

    // 游戏时间戳
    uint256 public gameCreatedAt;
    uint256 public gameJoinedAt;

    // 异常集合
    error WrongState(DiceGameState expected, DiceGameState actual);
    error InvalidParam(string message);
    error NotBetOwner(address caller, address expected);
    error DuplicateParticipant(address caller);
    error RepeatedRevealed(address caller);
    error BetMismatch(bytes32 expected, bytes32 actual);


    constructor(address tokenContractAddress){
        require(tokenContractAddress != address(0), "invaild tokenContractAddress");
        // 初始化时 让Stage2合约能知道Stage1的存在
        tokenContract = IStage1(tokenContractAddress);
    }

    // 第一阶段：A 下注 第一个人默认选小 1-3胜
    function createDiceGame(bytes32 _fingerPrintForA) external payable nonReentrant{
        // 状态机校验
        if (diceGameState != DiceGameState.None) revert WrongState(DiceGameState.None, diceGameState);
        // A 下注价格为0
        if (msg.value == 0) revert InvalidParam("bet amount must be greater than 0");
        // A 赌的结果 简单校验
        if (_fingerPrintForA == bytes32(0)) revert InvalidParam("fingerprint cannot be zero");

        gamblerA = msg.sender;
        betAmount = msg.value;
        fingerPrintForA = _fingerPrintForA; // A 的猜测哈希值
        revealedA = false;
        // 记录游戏创建时间
        gameCreatedAt = block.timestamp;
        // 状态转换
        diceGameState = DiceGameState.WaitingForB;
        // 记录赌局开始
        emit DiceGameCreated(gamblerA, betAmount, fingerPrintForA);
    }

    // 第二阶段 B 下注 默认选大 4-6胜
    function joinGame(bytes32 _fingerPrintForB) external payable nonReentrant {
        if (diceGameState != DiceGameState.WaitingForB) revert WrongState(DiceGameState.WaitingForB, diceGameState);
        // 不准同一个人同时参与一局游戏 防止刷token
        if (msg.sender == gamblerA) revert DuplicateParticipant(msg.sender);
        // 下注金额对等校验
        if (msg.value != betAmount) revert InvalidParam("bet amount must match game bet amount");
        // A 赌的结果 简单校验
        if (_fingerPrintForB == bytes32(0)) revert InvalidParam("fingerprint cannot be zero");

        gamblerB = msg.sender;
        fingerPrintForB = _fingerPrintForB;
        // 记录游戏加入时间
        gameJoinedAt = block.timestamp;
        diceGameState = DiceGameState.BothBetted;

        // 记录B加入
        emit DiceGameJoined(gamblerB, msg.value,fingerPrintForB);
    }

    // A 投注结果
    function revealA(bytes32 _secretA) external nonReentrant {
        if (diceGameState != DiceGameState.BothBetted) revert WrongState(DiceGameState.BothBetted, diceGameState);
        // 防止非本人揭示赌注
        if (msg.sender != gamblerA) revert NotBetOwner(msg.sender, gamblerA);
        // 防止重复揭示
        if (revealedA) revert RepeatedRevealed(msg.sender);
        // 校验赌注是否有效
        // 验证：哈希(_secretA) == 之前存储的 fingerPrintForA
        if (keccak256(abi.encodePacked(_secretA)) != fingerPrintForA) revert BetMismatch(fingerPrintForA, keccak256(abi.encodePacked(_secretA))); 

        secretA = _secretA;
        revealedA = true;
        // 记录事件
        emit BetForARevealed();
        // 如果此时B也已经揭示了 直接进入结算
        if (revealedB) _diceGameSettle(); 
    }


    // B 投注结果
    function revealB(bytes32 _secretB) external nonReentrant {
        if (diceGameState != DiceGameState.BothBetted) revert WrongState(DiceGameState.BothBetted, diceGameState);
        // 防止非本人揭示赌注
        if (msg.sender != gamblerB) revert NotBetOwner(msg.sender, gamblerB);
        // 防止重复揭示
        if (revealedB) revert RepeatedRevealed(msg.sender);
        // 校验赌注是否有效
        if (keccak256(abi.encodePacked(_secretB)) != fingerPrintForB) revert BetMismatch(fingerPrintForB, keccak256(abi.encodePacked(_secretB))); 

        secretB = _secretB;
        revealedB = true;
        // 记录事件
        emit BetForBRevealed();
        // 如果此时B也已经揭示了 直接进入结算
        if (revealedA) _diceGameSettle(); 
    }

    // 赌局结算 
    // 随机种子：使用 A 和 B 的私钥、区块号、时间戳和参与者地址
    // 结果：赢的人拿走所有赌注和stage1中token奖励
    function _diceGameSettle() private {
        // 使用多个熵源生成更安全的随机数
        // 包括：双方秘密、区块号、区块时间戳、参与者地址
        bytes32 randomSeed = keccak256(abi.encodePacked(
            secretA, 
            secretB, 
            block.number, 
            block.timestamp,
            gamblerA,
            gamblerB
        ));
        // 骰子结果：1-6
        uint256 n = (uint256(randomSeed) % 6) + 1;
        // 默认规则：1-3 A 胜，4-6 B 胜
        winner = n <= 3 ? gamblerA : gamblerB; 
        // 合约内全部赌注给winner
        uint256 profits = address(this).balance; 
        // stage1 中 额外给出奖励
        uint256 balanceOfStage1 = tokenContract.balanceOf(address(this)); 
        uint256 stage1TokenBonus = balanceOfStage1 >= TOKEN_BONUS ? TOKEN_BONUS : balanceOfStage1;

        // Checks-effects-interactions：先改状态、发事件，再对外转 ETH/代币（防重入）
        diceGameState = DiceGameState.Settled;
        emit DiceGameSettled(winner, profits, stage1TokenBonus);

        // 先 reset 再转账
        _reset(); 
        (bool sent, ) = payable(winner).call{value: profits}("");
        require(sent, "Bet profits failed to send");
        if (stage1TokenBonus > 0) {
            bool tokenSent = tokenContract.transfer(winner, stage1TokenBonus);
            require(tokenSent, "Stage1token bonus failed to send");
        }
    }


    // 清空赌局数据，可开下一局
    function _reset() private {
        gamblerA = address(0);
        gamblerB = address(0);
        betAmount = 0;
        fingerPrintForA = bytes32(0);
        fingerPrintForB = bytes32(0);
        secretA = bytes32(0);
        secretB = bytes32(0);
        revealedA = false;
        revealedB = false;
        winner = address(0);
        gameCreatedAt = 0;
        gameJoinedAt = 0;
        diceGameState = DiceGameState.None;
    }


    receive() external payable {}


    // 超时检查函数
    // 如果游戏超时，允许一方强制获胜
    function checkTimeout() external nonReentrant {
        // 只有在BothBetted状态下才能检查超时
        if (diceGameState != DiceGameState.BothBetted) revert WrongState(DiceGameState.BothBetted, diceGameState);

        // 检查是否超时
        if (block.timestamp <= gameJoinedAt + TIMEOUT_DURATION) revert InvalidParam("game has not timed out yet");

        // 超时处理：先揭示的一方获胜
        // 如果A已揭示而B未揭示，A获胜
        if (revealedA && !revealedB) {
            winner = gamblerA;
        } 
        // 如果B已揭示而A未揭示，B获胜
        else if (revealedB && !revealedA) {
            winner = gamblerB;
        }
        // 如果都未揭示或都已揭示（应该已结算），则不做处理
        else {
            revert InvalidParam("invalid timeout state: both revealed or none revealed");
        }

        // 合约内全部赌注给winner
        uint256 profits = address(this).balance; 
        // stage1 中 额外给出奖励
        uint256 balanceOfStage1 = tokenContract.balanceOf(address(this)); 
        uint256 stage1TokenBonus = balanceOfStage1 >= TOKEN_BONUS ? TOKEN_BONUS : balanceOfStage1;

        // Checks-effects-interactions：先改状态、发事件，再对外转 ETH/代币（防重入）
        diceGameState = DiceGameState.Settled;
        emit DiceGameSettled(winner, profits, stage1TokenBonus);

        // 先 reset 再转账
        _reset(); 
        (bool sent, ) = payable(winner).call{value: profits}("");
        require(sent, "Bet profits failed to send");
        if (stage1TokenBonus > 0) {
            bool tokenSent = tokenContract.transfer(winner, stage1TokenBonus);
            require(tokenSent, "Stage1token bonus failed to send");
        }
    }

    // 查询剩余超时时间（秒）
    function getRemainingTimeout() external view returns (uint256) {
        if (diceGameState != DiceGameState.BothBetted) return 0;
        if (block.timestamp > gameJoinedAt + TIMEOUT_DURATION) return 0;
        return gameJoinedAt + TIMEOUT_DURATION - block.timestamp;
    }

    // 取消游戏功能
    // 只有在WaitingForB状态下，创建者可以取消游戏
    function cancelGame() external nonReentrant {
        // 只有在WaitingForB状态下才能取消
        if (diceGameState != DiceGameState.WaitingForB) revert WrongState(DiceGameState.WaitingForB, diceGameState);
        // 只有游戏创建者可以取消
        if (msg.sender != gamblerA) revert NotBetOwner(msg.sender, gamblerA);
        // 检查是否超时（创建后30分钟内可取消）
        if (block.timestamp > gameCreatedAt + TIMEOUT_DURATION) revert InvalidParam("cancel period has expired");

        // 退还赌注给创建者
        uint256 refundAmount = betAmount;
        // 重置游戏状态
        _reset();

        // 退还ETH
        (bool sent, ) = payable(msg.sender).call{value: refundAmount}("");
        require(sent, "Refund failed");
    }

    // 查询游戏创建后剩余取消时间（秒）
    function getRemainingCancelTime() external view returns (uint256) {
        if (diceGameState != DiceGameState.WaitingForB) return 0;
        if (block.timestamp > gameCreatedAt + TIMEOUT_DURATION) return 0;
        return gameCreatedAt + TIMEOUT_DURATION - block.timestamp;
    }



}

contracts/Stage1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title Stage1 Token Contract
 * @dev 这是一个简单的 ERC20 代币合约，支持代币转账、铸造和卖出功能
 * 
 * 功能特性：
 * 1. 代币转账功能 (transfer)
 * 2. 铸造新代币 (mint) - 仅合约所有者可用
 * 3. 卖出代币换取 ETH (sell) - 按固定价格 600 wei/token
 * 4. 重入攻击防护
 * 5. 合约可被所有者关闭 (close)
 */
contract Stage1 {
    // ============================
    // 重入防护机制
    // ============================

    /**
     * @dev 重入防护锁，防止重入攻击
     * 在关键函数执行期间锁定，阻止嵌套调用
     */
    bool private _locked = false;

    /**
     * @dev 重入防护修饰器
     * 使用检查-效果-交互模式 (Checks-Effects-Interactions) 防止重入攻击
     * 
     * 工作原理：
     * 1. 检查：验证锁未被持有（允许调用）
     * 2. 设置：立即锁定
     * 3. 执行：运行函数主体
     * 4. 解锁：函数返回后释放锁
     * 
     * 注意：由于 Solidity 修饰器的执行顺序，
     * 锁定在函数主体之前设置，在函数主体之后释放
     */
    modifier nonReentrant() {
        require(!_locked, 'Reentrant call');
        _locked = true;
        _;
        _locked = false;
    }

    // ============================
    // 合约状态变量
    // ============================

    /// @dev 合约所有者地址，可用于铸造代币和关闭合约
    address payable public owner;

    // ============================
    // 事件定义
    // ============================

    /**
     * @dev 转账事件
     * @param from 代币转出地址
     * @param to 代币转入地址
     * @param value 转账数量
     */
    event Transfer(address indexed from, address indexed to, uint256 value);

    /**
     * @dev 铸造事件（代币增发）
     * @param to 获得新代币的地址
     * @param value 铸造的代币数量
     */
    event Mint(address indexed to, uint256 value);

    /**
     * @dev 卖出事件（代币销毁并换 ETH）
     * @param from 卖出代币的地址
     * @param value 卖出的代币数量
     */
    event Sell(address indexed from, uint256 value);

    // ============================
    // 常量定义
    // ============================

    /**
     * @dev 代币价格：600 wei 每个代币
     * @notice 这是固定价格，不可更改
     */
    uint128 private constant PRICE_WEI_PER_TOKEN = 600;

    // ============================
    // 内部状态变量
    // ============================

    /// @dev 代币总供应量
    uint256 private _totalSupply;

    /// @dev 代币名称（如 "MyToken"）
    string private _name;

    /// @dev 代币符号（如 "MTK"）
    string private _symbol;

    /**
     * @dev 地址到代币余额的映射
     * @notice 使用 private 修饰符防止直接访问，通过 balanceOf 函数查询
     */
    mapping(address => uint256) private _balances;

    // ============================
    // 构造函数
    // ============================

    /**
     * @dev 构造函数，初始化代币合约
     * @param name 代币名称
     * @param symbol 代币符号
     * 
     * @notice 部署时设置代币名称和符号，合约创建者为所有者
     * @notice 初始代币供应量为 0，需要通过 mint 铸造
     */
    constructor(string memory name, string memory symbol) {
        owner = payable(msg.sender);  // 记录合约部署者地址
        _name = name;
        _symbol = symbol;
    }

    // ============================
    // 只读函数 (View Functions)
    // ============================

    /**
     * @dev 获取代币名称
     * @return 代币名称字符串
     */
    function getName() external view returns (string memory) {
        return _name;
    }

    /**
     * @dev 获取代币总供应量
     * @return 代币总供应量
     */
    function totalSupply() external view returns (uint256) {
        return _totalSupply;
    }

    /**
     * @dev 获取代币符号
     * @return 代币符号字符串
     */
    function getSymbol() external view returns (string memory) {
        return _symbol;
    }

    /**
     * @dev 获取代币价格
     * @return 每个代币的价格（单位：wei）
     * 
     * @notice 纯函数，不读取状态，可用于 gas 优化
     */
    function getPrice() external pure returns (uint128) {
        return PRICE_WEI_PER_TOKEN;
    }

    /**
     * @dev 查询指定地址的代币余额
     * @param account 要查询的地址
     * @return 该地址持有的代币数量
     */
    function balanceOf(address account) external view returns (uint256) {
        return _balances[account];
    }

    // ============================
    // 状态变更函数 (State-Changing Functions)
    // ============================

    /**
     * @dev 转账功能 - 将代币从调用者账户转移到目标账户
     * @param to 接收代币的目标地址
     * @param value 要转账的代币数量
     * @return 是否转账成功
     * 
     * @dev 安全考虑：
     * 1. 检查目标地址不为零地址（防止发送到黑洞地址）
     * 2. 检查发送方余额充足
     * 3. 先减后加余额顺序（防止整数溢出）
     * 
     * @dev 事件说明：
     * 成功时触发 Transfer 事件，记录转账信息
     */
    function transfer(address to, uint256 value) external returns (bool) {
        // 地址有效性校验：不能转账到零地址
        require(to != address(0), "cannot transfer to 0x0");
        // 余额校验：发送方必须有足够的代币
        require(_balances[msg.sender] >= value, "no enough balance");

        // 防止 DAO 攻击：先减后加，确保余额更新原子性
        // 这样可以防止重入攻击和整数溢出问题
        _balances[msg.sender] -= value;
        _balances[to] += value;

        // 记录转账事件，供前端和监控系统监听
        emit Transfer(msg.sender, to, value);
        return true;
    }

    /**
     * @dev 铸造新代币 - 合约所有者专用
     * @param to 接收新代币的地址
     * @param value 要铸造的代币数量
     * @return 是否铸造成功
     * 
     * @dev 安全考虑：
     * 1. 仅允许合约所有者调用（防止非法增发）
     * 2. 检查目标地址不为零（防止烧毁代币）
     * 
     * @dev 经济机制：
     * - 铸造会增加总供应量 (_totalSupply)
     * - 代币直接添加到接收者余额
     * - 触发 Mint 事件记录增发
     * 
     * @notice 这个函数需要信任合约所有者，应在部署时设置合理的所有者权限
     */
    function mint(address to, uint256 value) external returns (bool) {
        // 权限校验：仅合约所有者可以铸造
        require(msg.sender == owner, "only owner may call");
        // 地址校验：不能铸造到零地址
        require(to != address(0), "mint to zero");

        // 增加总供应量
        _totalSupply += value;
        // 增加接收者余额
        _balances[to] += value;
        // 记录铸造事件
        emit Mint(to, value);

        return true;
    }

    /**
     * @dev 卖出代币 - 将代币兑换为 ETH
     * @param value 要卖出的代币数量
     * @return 是否卖出成功
     * 
     * @dev 工作流程：
     * 1. 校验卖出数量大于 0
     * 2. 校验用户有足够代币
     * 3. 校验合约有足够 ETH
     * 4. 扣除用户代币和总供应量
     * 5. 向用户支付 ETH
     * 
     * @dev 安全考虑：
     * 1. 使用 nonReentrant 修饰器防止重入攻击
     * 2. 使用 Checks-Effects-Interactions 模式
     * 3. 先更新状态（扣除代币），再转 ETH（外部调用）
     * 
     * @dev 价格机制：
     * - 单价：600 wei / token
     * - 总价 = 单价 × 数量
     * - 例如：卖出 10 个代币可获得 6000 wei (0.006 ETH)
     * 
     * @notice 重要：合约必须有足够的 ETH 储备才能成功卖出
     */
    function sell(uint256 value) external nonReentrant returns (bool) {
        // 数量校验：不能卖出 0 或负数
        require(value > 0, "cannot sell zero or below");
        // 余额校验：用户必须有足够的代币
        require(_balances[msg.sender] >= value, "no enough balance");

        // 计算应该支付给用户的 ETH 数量
        // 使用 uint256 确保乘法运算不溢出
        uint256 weiRequired = uint256(PRICE_WEI_PER_TOKEN) * value;

        // 合约余额校验：确保合约有足够 ETH 支付用户
        // 这是必要的，因为合约可能没有足够的 ETH 储备
        require(address(this).balance >= weiRequired, "contract insufficient ETH");

        // _checks-Effects-Interactions_：先更新状态，再进行外部调用

        // 扣除用户代币
        _balances[msg.sender] -= value;
        // 减少总供应量（代币被"烧毁"）
        _totalSupply -= value;

        // 记录卖出事件
        emit Sell(msg.sender, value);

        // 向用户支付 ETH
        // 使用 call 而不是 transfer，避免 gas 限制问题
        (bool sent, ) = payable(msg.sender).call{value: weiRequired}("");
        require(sent, "ETH transfer failed");
        return true;
    }

    /**
     * @dev 关闭合约 - 合约所有者专用
     * 
     * @dev 功能：
     * 1. 验证调用者是合约所有者
     * 2. 销毁合约，将合约剩余 ETH 转给所有者
     * 
     * @dev 安全考虑：
     * - 仅所有者可调用
     * - selfdestruct 是不可逆操作
     * 
     * @notice 谨慎使用，确保所有业务逻辑已完成后再调用
     */
    function close() external {
        // 权限校验：仅合约所有者
        require(msg.sender == owner, "only owner");
        // 销毁合约，将余额转给所有者
        selfdestruct(owner);
    }

    /**
     * @dev 接收 ETH 的回调函数
     * 
     * @dev 用途：
     * - 允许任何人向合约充值 ETH
     * - 这是卖出功能所必需的（需要 ETH 储备）
     * 
     * @notice 合约需要 ETH 储备才能支持卖出功能
     * @notice 如果不需要充值功能，可以移除此函数
     */
    receive() external payable {}
}

contracts/Stage2.sol.content:
pragma solidity ^0.8.0;

/**
    接口：调用外部合约Stage1的发放奖励和查询余额函数
**/
interface IStage1 {
    function transfer(address to, uint256 value) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract Stage2{
    // 游戏状态枚举
    enum DiceGameState { None, WaitingForB, BothBetted, Settled }
    // stateMachine
    DiceGameState public diceGameState;
    // 发放token合约对象
    IStage1 public tokenContract;
    // 每场赌约的固定token数
    uint16 public constant TOKEN_BONUS = 100; 
    // 超时时间（秒）：30分钟
    uint256 public constant TIMEOUT_DURATION = 30 * 60;

    // 事件
    event DiceGameCreated(address gamblerA, uint256 betAmount, bytes32 fingerPrintForA);
    event DiceGameJoined(address  gamblerB, uint256 betAmount, bytes32 fingerPrintForB);
    event BetForARevealed();
    event BetForBRevealed();
    event DiceGameSettled(address winner, uint256 profits, uint256 stage1TokenBonus);

    // A
    address public gamblerA;
    // A下注结果hash值
    bytes32 public fingerPrintForA;
    bytes32 public secretA;
    bool public revealedA;


    uint256 public betAmount;

    // B
    address public gamblerB;
    // B下注结果hash值
    bytes32 public fingerPrintForB;
    bytes32 public secretB;
    bool public revealedB;

    // winner
    address public winner;

    // 游戏时间戳
    uint256 public gameCreatedAt;
    uint256 public gameJoinedAt;

    // 异常集合
    error WrongState(DiceGameState expected, DiceGameState actual);
    error InvalidParam(string message);
    error NotBetOwner(address caller, address expected);
    error DuplicateParticipant(address caller);
    error RepeatedRevealed(address caller);
    error BetMismatch(bytes32 expected, bytes32 actual);


    constructor(address tokenContractAddress){
        require(tokenContractAddress != address(0), "invaild tokenContractAddress");
        // 初始化时 让Stage2合约能知道Stage1的存在
        tokenContract = IStage1(tokenContractAddress);
    }

    // 第一阶段：A 下注 第一个人默认选小 1-3胜
    function createDiceGame(bytes32 _fingerPrintForA) external payable{
        // 状态机校验
        if (diceGameState != DiceGameState.None) revert WrongState(DiceGameState.None, diceGameState);
        // A 下注价格为0
        if (msg.value == 0) revert InvalidParam("bet amount must be greater than 0");
        // A 赌的结果 简单校验
        if (_fingerPrintForA == bytes32(0)) revert InvalidParam("fingerprint cannot be zero");

        gamblerA = msg.sender;
        betAmount = msg.value;
        fingerPrintForA = _fingerPrintForA; // A 的猜测哈希值
        revealedA = false;
        // 记录游戏创建时间
        gameCreatedAt = block.timestamp;
        // 状态转换
        diceGameState = DiceGameState.WaitingForB;
        // 记录赌局开始
        emit DiceGameCreated(gamblerA, betAmount, fingerPrintForA);
    }

    // 第二阶段 B 下注 默认选大 4-6胜
    function joinGame(bytes32 _fingerPrintForB) external payable {
        if (diceGameState != DiceGameState.WaitingForB) revert WrongState(DiceGameState.WaitingForB, diceGameState);
        // 不准同一个人同时参与一局游戏 防止刷token
        if (msg.sender == gamblerA) revert DuplicateParticipant(msg.sender);
        // 下注金额对等校验
        if (msg.value != betAmount) revert InvalidParam("bet amount must match game bet amount");
        // A 赌的结果 简单校验
        if (_fingerPrintForB == bytes32(0)) revert InvalidParam("fingerprint cannot be zero");

        gamblerB = msg.sender;
        fingerPrintForB = _fingerPrintForB;
        // 记录游戏加入时间
        gameJoinedAt = block.timestamp;
        diceGameState = DiceGameState.BothBetted;

        // 记录B加入
        emit DiceGameJoined(gamblerB, msg.value,fingerPrintForB);
    }

    // A 投注结果
    function revealA(bytes32 _secretA) external {
        if (diceGameState != DiceGameState.BothBetted) revert WrongState(DiceGameState.BothBetted, diceGameState);
        // 防止非本人揭示赌注
        if (msg.sender != gamblerA) revert NotBetOwner(msg.sender, gamblerA);
        // 防止重复揭示
        if (revealedA) revert RepeatedRevealed(msg.sender);
        // 校验赌注是否有效
        // 验证：哈希(_secretA) == 之前存储的 fingerPrintForA
        if (keccak256(abi.encodePacked(_secretA)) != fingerPrintForA) revert BetMismatch(fingerPrintForA, keccak256(abi.encodePacked(_secretA))); 

        secretA = _secretA;
        revealedA = true;
        // 记录事件
        emit BetForARevealed();
        // 如果此时B也已经揭示了 直接进入结算
        if (revealedB) _diceGameSettle(); 
    }


    // B 投注结果（说明同 revealA）
    function revealB(bytes32 _secretB) external {
        if (diceGameState != DiceGameState.BothBetted) revert WrongState(DiceGameState.BothBetted, diceGameState);
        // 防止非本人揭示赌注
        if (msg.sender != gamblerB) revert NotBetOwner(msg.sender, gamblerB);
        // 防止重复揭示
        if (revealedB) revert RepeatedRevealed(msg.sender);
        // 校验赌注是否有效
        if (keccak256(abi.encodePacked(_secretB)) != fingerPrintForB) revert BetMismatch(fingerPrintForB, keccak256(abi.encodePacked(_secretB))); 

        secretB = _secretB;
        revealedB = true;
        // 记录事件
        emit BetForBRevealed();
        // 如果此时B也已经揭示了 直接进入结算
        if (revealedA) _diceGameSettle(); 
    }

    // 赌局结算 
    // 随机种子：使用 A 和 B 的私钥、区块号、时间戳和参与者地址
    // 结果：赢的人拿走所有赌注和stage1中token奖励
    function _diceGameSettle() private {
        // 使用多个熵源生成更安全的随机数
        // 包括：双方秘密、区块号、区块时间戳、参与者地址
        bytes32 randomSeed = keccak256(abi.encodePacked(
            secretA, 
            secretB, 
            block.number, 
            block.timestamp,
            gamblerA,
            gamblerB
        ));
        // 骰子结果：1-6
        uint256 n = (uint256(randomSeed) % 6) + 1;
        // 默认规则：1-3 A 胜，4-6 B 胜
        winner = n <= 3 ? gamblerA : gamblerB; 
        // 合约内全部赌注给winner
        uint256 profits = address(this).balance; 
        // stage1 中 额外给出奖励
        uint256 balanceOfStage1 = tokenContract.balanceOf(address(this)); 
        uint256 stage1TokenBonus = balanceOfStage1 >= TOKEN_BONUS ? TOKEN_BONUS : balanceOfStage1;

    // Checks-effects-interactions：先改状态、发事件，再对外转 ETH/代币
        // 注意：必须在外部转账之后再 _reset()，否则 winner 会被清空（变成 address(0)）
        address localWinner = winner;
        uint256 localProfits = profits;
        uint256 localTokenBonus = stage1TokenBonus;
        diceGameState = DiceGameState.Settled;
        emit DiceGameSettled(localWinner, localProfits, localTokenBonus);

        // 先对外转账，再清空状态（确保资金发给正确 winner）
        (bool sent, ) = payable(localWinner).call{value: localProfits}("");
        require(sent, "Bet profits failed to send");
        if (localTokenBonus > 0) {
            bool tokenSent = tokenContract.transfer(localWinner, localTokenBonus);
            require(tokenSent, "Stage1token bonus failed to send");
        }

        _reset();
    }


    // 清空赌局数据，可开下一局
    function _reset() private {
        gamblerA = address(0);
        gamblerB = address(0);
        betAmount = 0;
        fingerPrintForA = bytes32(0);
        fingerPrintForB = bytes32(0);
        secretA = bytes32(0);
        secretB = bytes32(0);
        revealedA = false;
        revealedB = false;
        winner = address(0);
        gameCreatedAt = 0;
        gameJoinedAt = 0;
        diceGameState = DiceGameState.None;
    }


    receive() external payable {}


    // 超时检查函数
    // 如果游戏超时，允许一方强制获胜
    function checkTimeout() external {
        // 只有在BothBetted状态下才能检查超时
        if (diceGameState != DiceGameState.BothBetted) revert WrongState(DiceGameState.BothBetted, diceGameState);

        // 检查是否超时
        if (block.timestamp <= gameJoinedAt + TIMEOUT_DURATION) revert InvalidParam("game has not timed out yet");

        // 超时处理：先揭示的一方获胜
        // 如果A已揭示而B未揭示，A获胜
        if (revealedA && !revealedB) {
            winner = gamblerA;
        } 
        // 如果B已揭示而A未揭示，B获胜
        else if (revealedB && !revealedA) {
            winner = gamblerB;
        }
        // 如果都未揭示或都已揭示（应该已结算），则不做处理
        else {
            revert InvalidParam("invalid timeout state: both revealed or none revealed");
        }

        // 合约内全部赌注给winner
        uint256 profits = address(this).balance; 
        // stage1 中 额外给出奖励
        uint256 balanceOfStage1 = tokenContract.balanceOf(address(this)); 
        uint256 stage1TokenBonus = balanceOfStage1 >= TOKEN_BONUS ? TOKEN_BONUS : balanceOfStage1;


        // 注意：必须在外部转账之后再 _reset()，否则 winner 会被清空（变成 address(0)）
        address localWinner = winner;
        uint256 localProfits = profits;
        uint256 localTokenBonus = stage1TokenBonus;
        diceGameState = DiceGameState.Settled;
        emit DiceGameSettled(localWinner, localProfits, localTokenBonus);

        // 先对外转账，再清空状态（确保资金发给正确 winner）
        (bool sent, ) = payable(localWinner).call{value: localProfits}("");
        require(sent, "Bet profits failed to send");
        if (localTokenBonus > 0) {
            bool tokenSent = tokenContract.transfer(localWinner, localTokenBonus);
            require(tokenSent, "Stage1token bonus failed to send");
        }

        _reset();
    }

    // 查询剩余超时时间（秒）
    function getRemainingTimeout() external view returns (uint256) {
        if (diceGameState != DiceGameState.BothBetted) return 0;
        if (block.timestamp > gameJoinedAt + TIMEOUT_DURATION) return 0;
        return gameJoinedAt + TIMEOUT_DURATION - block.timestamp;
    }

    // 取消游戏功能
    // 只有在WaitingForB状态下，创建者可以取消游戏
    function cancelGame() external {
        // 只有在WaitingForB状态下才能取消
        if (diceGameState != DiceGameState.WaitingForB) revert WrongState(DiceGameState.WaitingForB, diceGameState);
        // 只有游戏创建者可以取消
        if (msg.sender != gamblerA) revert NotBetOwner(msg.sender, gamblerA);
        // 检查是否超时（创建后30分钟内可取消）
        if (block.timestamp > gameCreatedAt + TIMEOUT_DURATION) revert InvalidParam("cancel period has expired");

        // 退还赌注给创建者
        uint256 refundAmount = betAmount;
        // 重置游戏状态
        _reset();

        // 退还ETH
        (bool sent, ) = payable(msg.sender).call{value: refundAmount}("");
        require(sent, "Refund failed");
    }

    // 查询游戏创建后剩余取消时间（秒）
    function getRemainingCancelTime() external view returns (uint256) {
        if (diceGameState != DiceGameState.WaitingForB) return 0;
        if (block.timestamp > gameCreatedAt + TIMEOUT_DURATION) return 0;
        return gameCreatedAt + TIMEOUT_DURATION - block.timestamp;
    }

}
